form:Form.form:Scripts:
		function LoadForm()
{             
	OnLoad();
	if(Ctrl("estado").GetXValue()=="D" || Ctrl("estado").GetXValue()=="R")
	{                                    
		CtrlEnabled("vgPERSONAL_BASE", false);
		CtrlEnabled("vgPERSONAL", false);
		CtrlEnabled("vgPERSONAL", false);
		CtrlEnabled("vgPOSICION", false);
		CtrlEnabled("vgPUESTO", false);
		CtrlEnabled("vgCLASE", false);
		CtrlEnabled("vgVERSION", false);
		CtrlEnabled("vgVISTA", false);
	}
	if(Ctrl("estado").GetXValue()=="V")
	{
		CtrlEnabled("RECHAZAR", false);
		CtrlEnabled("VIGENTE", false);
	}
	if(Ctrl("estado").GetXValue()=="P")
	{
		CtrlEnabled("DISCONTINUAR", false);
		CtrlEnabled("PLANIFICAR", false);
	}
}

function ExternButtonRefresh()
{                  
	var oi_estructura_root=null;
	var EstData,FirstPer=null;

	//Personal
	CtrlEnabled("LEG_ADD"   , false);
	CtrlEnabled("LEG_DEL"   , false);
	CtrlEnabled("LEG_CHG"   , false);
	CtrlEnabled("LEG_EGR"   , false);
	CtrlEnabled("LEG_RESP"  , false);
	CtrlEnabled("LEG_NORESP", false);

	//Estructura
	CtrlEnabled("ESTR_ASIG"    , false);   
	CtrlEnabled("ESTR_CAMB"    , false);
	CtrlEnabled("ESTR_ADD"    , false);
	CtrlEnabled("ESTR_ADD_FIC", false);
	CtrlEnabled("ESTR_DEL"    , false);
	CtrlEnabled("ESTR_EDT"    , false);
	CtrlEnabled("ESTR_MOVE"   , false);
	CtrlEnabled("ESTR_SHW"    , false);
	CtrlEnabled("PUESTO_SHW"  , false);
	CtrlEnabled("PUESTO_REP"  , false);
	CtrlEnabled("ESTR_STAFF"  , false);

	//Vista
	CtrlEnabled("VISTA_ADD", false);
	CtrlEnabled("VISTA_DEL", false);

	//Obtengo la Estructura
	EstData=(g_oi_estr_select!=null?g_lst_Estr["K"+g_oi_estr_select]:null);
	if (g_mode!=2)
	{                          
		if (EstData!=null)
		{                 
			if (EstData.GetAttr("fic")=="1")
			{   
				CtrlEnabled("ESTR_ASIG"    , true);
				CtrlEnabled("ESTR_ADD"    , true);
				CtrlEnabled("ESTR_ADD_FIC", true);
				CtrlEnabled("ESTR_DEL"    , (g_oi_estr_select!=g_oi_estr_root && EstData.GetAttr("child_count")=="0")?true:false);
				if(Ctrl("estado").GetXValue()=="P")	
					CtrlEnabled("ESTR_CAMB"    , true);		
			} else
			{

				if (EstData.GetAttr("extern")!="1" && EstData.GetAttr("l_staff")!="1")
				{
					if (EstData.GetAttr("vista")!="") CtrlEnabled("VISTA_DEL", true); 
					                             else CtrlEnabled("VISTA_ADD", true);
				}

				//Personal  
				CtrlEnabled("LEG_NORESP", EstData.GetAttr("nombre")==""?false:true);

				//Estructura             
				CtrlEnabled("ESTR_DEL"  , (g_oi_estr_select!=g_oi_estr_root && EstData.GetAttr("child_count")=="0")?true:false);
				CtrlEnabled("ESTR_STAFF"  , (g_oi_estr_select!=g_oi_estr_root && EstData.GetAttr("child_count")=="0")?true:false);
				if(Ctrl("estado").GetXValue()!="P")
				{
					CtrlEnabled("ESTR_EDT"  , true); 
					CtrlEnabled("ESTR_SHW"  , true); 
					CtrlEnabled("PUESTO_SHW", true); 
					CtrlEnabled("PUESTO_REP", true);
				}

				if (EstData.GetAttr("l_staff")!="1")
				{                                   

					//Estructura
					CtrlEnabled("ESTR_ASIG", true);
					CtrlEnabled("ESTR_ADD"    , true);
					CtrlEnabled("ESTR_ADD_FIC", true);
					CtrlEnabled("ESTR_MOVE"   , g_oi_estr_select!=g_oi_estr_root?true:false);
					if(Ctrl("estado").GetXValue()=="P")	
						CtrlEnabled("ESTR_CAMB"    , true);	
					if(Ctrl("estado").GetXValue()!="P")
					{ 
					  CtrlEnabled("ESTR_EDT", g_oi_estr_select!=g_oi_estr_root?true:false);
					  CtrlEnabled("ESTR_SHW", g_oi_estr_select!=g_oi_estr_root?true:false);
					  CtrlEnabled("PUESTO_SHW", g_oi_estr_select!=g_oi_estr_root?true:false);
					  CtrlEnabled("PUESTO_REP", g_oi_estr_select!=g_oi_estr_root?true:false);
					}
				}
			}
		}

	} else
	{        
		if (EstData!=null)
		{          
			if (g_oi_estr_select==g_oi_estr2_show)
			{       
				FirstPer=EstData.FindElement("personas");
				if (FirstPer!=null) FirstPer=FirstPer.FirstChild();
				if (FirstPer!=null && FirstPer.GetAttr("resp")!="1") FirstPer=null;

			  //Personal
				CtrlEnabled("LEG_ADD"     , true);     
				CtrlEnabled("LEG_EGR"     , g_oi_legajo_select==null?false:true);
				CtrlEnabled("LEG_RESP"    , g_oi_legajo_select!=null && (FirstPer==null || (FirstPer!=null && FirstPer.GetAttr("oi_legajo")!=g_oi_legajo_select.toString()))?true:false);
				CtrlEnabled("LEG_NORESP"  , FirstPer!=null?true:false);
				if(Ctrl("estado").GetXValue()=="P")
				{
					CtrlEnabled("ESTR_CAMB", true);
					CtrlEnabled("LEG_DEL", false);
					CtrlEnabled("LEG_CHG", false);
				}
				else
				{
					CtrlEnabled("LEG_DEL", g_oi_legajo_select==null?false:true);
					CtrlEnabled("LEG_CHG", g_oi_legajo_select==null?false:true);
				}
			} 
		} 
	}
}


//legajos
function SetResponsable()
{
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","SETRESP",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" OI_EMPRESA="'+Ctrl("oi_empresa").GetXValue()+'" oi_clase_org="'+Ctrl('oi_clase_org').GetXValue()+'" VALUE="'+g_oi_legajo_select+'" />',new ObjtectResult2(),"L");
}

function UnSetResponsable()
{                           
	if (g_mode==2)
	{   
		EstData=g_lst_Estr["K"+g_oi_estr_select]; 
		oi_legajo=EstData.FindElement("personas").FirstChild().GetAttr("oi_legajo");
	} else
	{         
		oi_legajo=g_oi_legajo_select;
	}

	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","UNSETRESP",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" OI_EMPRESA="'+Ctrl("oi_empresa").GetXValue()+'" oi_clase_org="'+Ctrl('oi_clase_org').GetXValue()+'" VALUE="'+oi_legajo+'" />',new ObjtectResult2(),"L");
}

function MarkStaff()
{
	EstData=g_lst_Estr["K"+g_oi_estr_select];
	openNewFlowWait("NucleusRH.Base.Organizacion.Puestos.POSICION.flow","SETSTAFF",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" estado="'+Ctrl('estado').GetXValue()+'" />',new ObjtectResult2(),"L");
}                


