			openNewFlowWait("NucleusRH.Base.Organizacion.Puestos.POSICION.flow","EGRLEGAJO",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" OI_EMPRESA="'+Ctrl("oi_empresa").GetXValue()+'" oi_clase_org="'+Ctrl('oi_clase_org').GetXValue()+'" VALUE="'+g_oi_legajo_select+'" />',new ObjtectResult2(),"L");
		if(Ctrl("estado").GetXValue()=="P")	
			openNewFlowWait("NucleusRH.Base.Organizacion.Puestos.POSICION.flow","DELLEGAJOPLANIFICADO",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" OI_EMPRESA="'+Ctrl("oi_empresa").GetXValue()+'" oi_clase_org="'+Ctrl('oi_clase_org').GetXValue()+'" VALUE="'+g_oi_legajo_select+'" />',new ObjtectResult2(),"L");
	}

}

