}               

function DelPosicion()
{   
	//Hace la consulta para verificar si la unidad organizativa asociada esta siendo utilizada en otra estructura
	var param="<DATO oi_estructura='"+g_oi_estr_select+"' />";
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
	var result = nSQL.GetOBJ(Ctrl("main").getResource("qry:CONFIRM_DELETE_POS_VIGENTE"), param); 

	//Hace la consulta para ver si la estructura a eliminar tiene o no trayectoria de legajos
	var result2 = nSQL.GetOBJ(Ctrl("main").getResource("qry:POSICION_PER"), param);     

	//Mensaje de confirmacion antes de eliminar la estructura
	var msg="¿Esta seguro que desea eliminar la Posición?";       

	//Si la estructura no tiene legajos asignados
	if(result2.flag!=2)
	{
	//Si no esta siendo utilizada en una estructura vigente se modifica posicion y unidad organizativa
	if(result.estrvigente=="0")
		{
		//Si esta siendo utilizada en una estructura no vigente o tiene legajos asignados como trayectoria solo se edita la posicion 
		if(result.estrnovigente=="1" || result2.flag=="1")   
		msg="Si elimina la estructura, la posición pasará a estar no vigente. ¿Desea continuar con la operación de todos modos?";
		//Si no esta siendo utilizada en ninguna estructura y no tiene legajos asignados como trayectoria, se modifica posicion y se elimina la unidad organizativa
		else
		msg="Si elimina la estructura, se eliminará la posición y la unidad organizativa asociada. ¿Desea continuar con la operación de todos modos?";
		}
	else
		{
		msg="Si elimina la estructura, la posición continuará vigente dado que es utilizada por otra estructura. ¿Desea continuar con la operación de todos modos?";
		}
	}

	EstData=(g_oi_estr_select!=null?g_lst_Estr["K"+g_oi_estr_select]:null);
	if (EstData.GetAttr("fic")=="1")
	{     
	  openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","DELESTR",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" VALUE="" />',new ObjtectResult2(),"L");
	} 
	else
	{    
		if (confirm(msg))       
			{
		if(Ctrl("estado").GetXValue()=="V")
			openNewFlowWait("NucleusRH.Base.Organizacion.Puestos.POSICION.flow","DELPOSICION",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" OI_EMPRESA="'+Ctrl("oi_empresa").GetXValue()+'" oi_clase_org="'+Ctrl('oi_clase_org').GetXValue()+'" VALUE="'+g_oi_legajo_select+'" />',new ObjtectResult2(),"L");
	  	if(Ctrl("estado").GetXValue()=="P")
	 	 	openNewFlowWait("NucleusRH.Base.Organizacion.Puestos.POSICION.flow","DELPOSICION",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" OI_EMPRESA="'+Ctrl("oi_empresa").GetXValue()+'" oi_clase_org="'+Ctrl('oi_clase_org').GetXValue()+'" VALUE="'+g_oi_legajo_select+'" />',new ObjtectResult2(),"L");
	 	 	}
	}
}

