}                  

function DelVista()
{
	EstData=g_lst_Estr["K"+g_oi_estr_select];
	if (confirm("¿Está seguro que desea quitar la Vista?"))
		openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUC_PERS.flow","DELVISTA",'<ID OI_ESTRUCTURA="'+g_oi_estr_select+'" VALUE="'+EstData.GetAttr("vista")+'" />',new ObjtectResult2(),"L");
}

function ObjtectResult2()
{
	this.processResult= function(xmlin)
	{
		var xml_xmlin = new NomadXML(xmlin);
		if (xml_xmlin.GetAttr("error") != "") alert(xml_xmlin.GetAttr("error"));
		OrgClearCache();
		DrawHTML();
	}
}
